use std::fs;
use std::path::Path;

pub fn copy_files(src: &str, dst: &str) -> Result<usize, std::io::Error> {
    let mut count: usize = 0;
    for entry in fs::read_dir(src)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_file() {
            let dest = Path::new(dst).join(entry.file_name());
            fs::copy(&path, &dest)?;
            count += 1;
        }
    }
    Ok(count)
}

