use std::sync::{Arc, Mutex};
use std::thread;

pub fn parallel_sum(data: &[i32], num_threads: usize) -> i32 {
    let total = Arc::new(Mutex::new(0i32));
    let chunk_size = data.len() / num_threads;

    let handles: Vec<_> = data.chunks(chunk_size).map(|chunk| {
        let total = total.clone();
        let chunk = chunk.to_vec();
        thread::spawn(move || {
            let sum: i32 = chunk.iter().sum();
            let mut guard = total.lock().unwrap();
            *guard += sum;
        })
    }).collect();

    for h in handles {
        h.join().unwrap();
    }

    *total.lock().unwrap()
}

