use std::sync::Arc;
use tokio::sync::mpsc;

pub async fn data_pipeline(input: Vec<String>) -> Vec<String> {
    // Stage 1: Process
    let processed: Vec<String> = futures::future::join_all(
        input.into_iter().map(|data| async move {
            // Worker agent processing
            data.to_uppercase()
        })
    ).await;

    // Stage 2: Validate
    let validated: Vec<String> = futures::future::join_all(
        processed.into_iter().map(|item| async move {
            // Validator agent
            item
        })
    ).await;

    // Stage 3: Write
    let results: Vec<String> = futures::future::join_all(
        validated.into_iter().map(|item| async move {
            // Writer agent
            item
        })
    ).await;

    results
}
